import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"83. Saturday And Sunday Work","description":"","frontmatter":{"title":"83. Saturday And Sunday Work","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","rosters","wages"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.md"};function s(d,e,i,l,p,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_83-saturday-and-sunday-work" tabindex="-1">83. Saturday And Sunday Work <a class="header-anchor" href="#_83-saturday-and-sunday-work" aria-label="Permalink to &quot;83. Saturday And Sunday Work&quot;">​</a></h1><p>Note: The term ‘ordinary hours of work’ is a reference to hours of work that are not at overtime rates.</p><p><strong>83.1</strong> This clause shall not apply to Employees above the classification of RPN 5 excepting Employees classified as Nurse Practitioner or those performing direct clinical work, who are entitled to the benefit of this clause.</p><p><strong>83.2</strong> Payment for all ordinary hours of work performed between midnight Friday and midnight Sunday (inclusive) shall be paid for at the rate of time and one half.</p><p><strong>83.3</strong> If the Saturday or Sunday work involves duty in excess of the prescribed ordinary rostered hours the excess period will be paid at the rate of double time.</p><p><strong>83.4</strong> For a casual Employee all ordinary hours of work between midnight on Friday and midnight on Sunday will be paid for at the rate of 187.5%. from the commencement of this Agreement.</p><p><strong>83.5</strong> Except in circumstances of a redeployment, a part-time Employee who was also a part-time Employee of the Department as at 19 December 1997 and who became employed (and continues to be employed) by an Employer who is a respondent to this Agreement, shall be paid a 100% shift penalty payment for all work performed on a Sunday. For the avoidance of doubt, such an Employee will not also be entitled to receive the penalties described above.</p><p>Plain language terms: weekend penalty, weekend loading, weekend rates.</p>',8)])])}const c=a(n,[["render",s]]);export{u as __pageData,c as default};
